histrix.customScript:
var css = "\
.path {\
  position: absolute;\
  overflow: hidden;\
  width: 100%;\
  height: 150px;\
  background-color: transparent;\
  margin: auto;\
}\
.shape {\
  position: absolute;\
  left: 0;\
  background-color: lime;\
  width: 100%;\
  height: 3px;\
  display: block;\
  top: 0;\
  x-transition: all 1s ease-in-out; \
  animation: ani 4s infinite;\
}\
@keyframes ani {\
  0% { top: 0; }\
  50% { top: 150px;}\
  100% {top: 0;}\
}";

$("<style>")
    .prop("type", "text/css")
    .html(css).appendTo("head");


    $('[instance="[__instance__]"] [name="resta"]').change(function(){
  $('[instance="[__instance__]"] [name="stkdeposito_origen_id"]').closest('tr').toggle();
    });



    Histrix.audioCtx = new (window.AudioContext || 

    window.webkitAudioContext || window.audioContext);

    //All arguments are optional:

    //duration of the tone in milliseconds. Default is 500
    //frequency of the tone in hertz. default is 440
    //volume of the tone. Default is 1, off is 0.
    //type of tone. Possible values are sine, square, sawtooth, triangle, and custom. Default is sine.
    //callback to use on end of tone
    function beep(duration, frequency, volume, type, callback) {
        var oscillator = Histrix.audioCtx.createOscillator();
        var gainNode = Histrix.audioCtx.createGain();

        oscillator.connect(gainNode);
        gainNode.connect(Histrix.audioCtx.destination);

        if (volume){gainNode.gain.value = volume;};
        if (frequency){oscillator.frequency.value = frequency;}
        if (type){oscillator.type = type;}
        if (callback){oscillator.onended = callback;}

        oscillator.start();
        setTimeout(function(){oscillator.stop()}, (duration ? duration : 500));
    };



    Histrix.scanQR = function scanQR() {

      $('#vidscan').remove();
      $('#preview').remove();

      var videoPreview = $('<div id="vidscan" style="width: 100%; height: 150px; overflow: hidden;"><div class="path"><span id="elem" class="shape trail"></span></div><video id="preview" style="width: 100%; ">Iniciando Cámara</video></div>');

      var $barcode = $('[instance="[__instance__]"] [name="barcode"]');

      $barcode.before(videoPreview);


      let scanner = new Instascan.Scanner({ 
          video: document.getElementById('preview'),
          mirror: false,
          backgroundScan: true,
        });

      Instascan.Camera.getCameras().then(function (cameras) {
        if (cameras.length > 0) {

          scanner.start(cameras[cameras.length - 1]);

        } else {
          Histrix.showMsg('No cameras found.', false, {type:'error'});
        }
      }).catch(function (e) {
          Histrix.showMsg('cath error', false, {type:'error'});
            console.error(e);
      });

      var onScan = function (content) {
        beep(1,2000);
        var data = content + '';
        var art =  data.split("/")[1];
        var locacion =  data.split("/")[0];

        $('[name="barcode"]', $('#preview').closest('form')).val(content).css({'border': '2px solid lime'}).change();

        $('[name="stkarticulo_id"]', $('#preview').closest('form')).val(art).change();

        $('[name="stklocacion_id"]', $('#preview').closest('form')).val(locacion).change();

        $('[name="cantidad"]', $('#preview').closest('form')).focus();
        Histrix.showMsg('Scan: '+ content, false, {timeOut:2});

      };

        $('[name="barcode"]', $('#preview').closest('form')).change(function(){
            var data = $(this).val();
      var art =  data.split("/")[1];
          var locacion =  data.split("/")[0];

            $('[name="stkarticulo_id"]', $('#preview').closest('form')).val(art).change();

      $('[name="stklocacion_id"]', $('#preview').closest('form')).val(locacion).change();

  });


      $(scanner).off('scan', "**");
      scanner.on('scan', onScan);

      return scanner;
    }



    if (typeof(Instascan) == 'object') {
      $(Histrix.scanner).off('scan', "**");
      Histrix.scanner = Histrix.scanQR();
    } else {
      $.getScript(Histrix.mainUrl()+'/web/vendor/instascan.min/index.js', function (){
          Histrix.scanner = Histrix.scanQR();
      });
    }
